const body = $('Webhook').first().json.body || $('Webhook').first().json;
const action = body.action;
const params = body.params || {};

// Build SQL based on action
let sql = '';
let responseData = null;

switch (action) {
  // ── DASHBOARD ──
  case 'dashboard': {
    sql = `
      SELECT json_build_object(
        'balance', (SELECT row_to_json(t) FROM (SELECT balance, spend_rate_per_hour, hours_remaining, collected_at FROM balance_history ORDER BY collected_at DESC LIMIT 1) t),
        'emergency', (SELECT row_to_json(t) FROM (SELECT is_active, trigger_reason, activated_at, auto_deactivate_at FROM emergency_state WHERE is_active = TRUE ORDER BY activated_at DESC LIMIT 1) t),
        'today_stats', (SELECT row_to_json(t) FROM (SELECT COUNT(*) as total_ads, COALESCE(SUM(money),0) as total_spend, COALESCE(SUM(postbacks_confirmed_money),0) as total_revenue, COALESCE(SUM(profit),0) as total_profit FROM ad_stats WHERE date = CURRENT_DATE) t),
        'teaser_counts', (SELECT json_agg(row_to_json(t)) FROM (SELECT state, COUNT(*) as cnt FROM teasers GROUP BY state) t),
        'bid_changes_24h', (SELECT COUNT(*) FROM bid_history WHERE changed_at >= NOW() - INTERVAL '24 hours'),
        'anomalies_open', (SELECT COUNT(*) FROM anomalies WHERE resolved = FALSE),
        'conservative_mode', (SELECT row_to_json(t) FROM (SELECT locked_by, expires_at FROM workflow_locks WHERE lock_name = 'conservative_mode' AND expires_at > NOW()) t)
      ) as data
    `;
    break;
  }

  // ── CONFIG LIST ──
  case 'config_list': {
    sql = `SELECT id, category, key, value, value_type, label, description, min_value, max_value, updated_at FROM bot_config ORDER BY category, id`;
    break;
  }

  // ── CONFIG UPDATE ──
  case 'config_update': {
    const updates = params.updates || [];
    if (updates.length === 0) {
      return [{ json: { error: 'No updates' } }];
    }
    const parts = updates.map(u =>
      `UPDATE bot_config SET value = '${String(u.value).replace(/'/g, "''")}', updated_at = NOW() WHERE id = ${parseInt(u.id)}`
    );
    sql = parts.join(';\n') + `;\nSELECT 'ok' as result, ${updates.length} as updated`;
    break;
  }

  // ── GEO PAYOUTS ──
  case 'geo_list': {
    sql = `SELECT id, country_code, country_name, geo_id, vertical, avg_payout, avg_approval, max_cpl, min_bid, max_bid, is_active, notes, updated_at FROM geo_payouts ORDER BY country_code`;
    break;
  }
  case 'geo_update': {
    const id = parseInt(params.id);
    const sets = [];
    for (const [k, v] of Object.entries(params.fields || {})) {
      if (['avg_payout','avg_approval','min_bid','max_bid','is_active','notes','country_name','geo_id','vertical'].includes(k)) {
        sets.push(`${k} = '${String(v).replace(/'/g, "''")}'`);
      }
    }
    sets.push('updated_at = NOW()');
    sql = `UPDATE geo_payouts SET ${sets.join(', ')} WHERE id = ${id}; SELECT 'ok' as result`;
    break;
  }
  case 'geo_create': {
    const f = params.fields || {};
    sql = `INSERT INTO geo_payouts (country_code, country_name, geo_id, vertical, avg_payout, avg_approval, min_bid, max_bid, is_active, notes)
      VALUES ('${(f.country_code||'').replace(/'/g,"''")}', '${(f.country_name||'').replace(/'/g,"''")}', ${parseInt(f.geo_id)||'NULL'}, '${(f.vertical||'crypto').replace(/'/g,"''")}', ${parseFloat(f.avg_payout)||0}, ${parseFloat(f.avg_approval)||0}, ${parseFloat(f.min_bid)||0.01}, ${parseFloat(f.max_bid)||0.15}, ${f.is_active !== false}, ${f.notes ? "'" + f.notes.replace(/'/g,"''") + "'" : 'NULL'})
      ON CONFLICT (country_code) DO UPDATE SET country_name=EXCLUDED.country_name, geo_id=EXCLUDED.geo_id, avg_payout=EXCLUDED.avg_payout, avg_approval=EXCLUDED.avg_approval, min_bid=EXCLUDED.min_bid, max_bid=EXCLUDED.max_bid, is_active=EXCLUDED.is_active, notes=EXCLUDED.notes, updated_at=NOW();
      SELECT 'ok' as result`;
    break;
  }
  case 'geo_delete': {
    sql = `DELETE FROM geo_payouts WHERE id = ${parseInt(params.id)}; SELECT 'ok' as result`;
    break;
  }

  // ── CAMPAIGNS & GROUPS HIERARCHY ──
  case 'campaigns_tree': {
    sql = `SELECT json_build_object(
      'campaigns', (SELECT COALESCE(json_agg(row_to_json(c)), '[]'::json) FROM (
        SELECT tc.campaign_id, COALESCE(cp.name, tc.campaign_name, 'Campaign #' || tc.campaign_id) as name, cp.campaign_type_id, cp.status, cp.daily_money_limit, cp.total_money_limit,
          (SELECT COALESCE(SUM(s.money),0) FROM ad_stats s JOIN teasers t ON t.ad_id = s.ad_id WHERE t.campaign_id = tc.campaign_id AND s.date = CURRENT_DATE) as today_spend,
          (SELECT COALESCE(SUM(s.profit),0) FROM ad_stats s JOIN teasers t ON t.ad_id = s.ad_id WHERE t.campaign_id = tc.campaign_id AND s.date = CURRENT_DATE) as today_profit,
          tc.total_ads, tc.active_ads
        FROM (SELECT campaign_id, COUNT(*) as total_ads, COUNT(*) FILTER (WHERE geozo_status_id = 5) as active_ads, MAX(campaign_name) as campaign_name FROM teasers WHERE campaign_id IS NOT NULL GROUP BY campaign_id) tc
        LEFT JOIN campaigns cp ON cp.campaign_id = tc.campaign_id
        ORDER BY tc.campaign_id
      ) c),
      'groups', (SELECT COALESCE(json_agg(row_to_json(g)), '[]'::json) FROM (
        SELECT tg.ad_group_id, tg.campaign_id, COALESCE(ag.name, tg.group_ad_name, 'Group #' || tg.ad_group_id) as name, ag.status,
          (SELECT COALESCE(SUM(s.money),0) FROM ad_stats s JOIN teasers t ON t.ad_id = s.ad_id WHERE t.ad_group_id = tg.ad_group_id AND s.date = CURRENT_DATE) as today_spend,
          (SELECT COALESCE(SUM(s.profit),0) FROM ad_stats s JOIN teasers t ON t.ad_id = s.ad_id WHERE t.ad_group_id = tg.ad_group_id AND s.date = CURRENT_DATE) as today_profit,
          tg.ad_count, tg.active_count
        FROM (SELECT ad_group_id, MIN(campaign_id) as campaign_id, COUNT(*) as ad_count, COUNT(*) FILTER (WHERE geozo_status_id = 5) as active_count, MAX(group_ad_name) as group_ad_name FROM teasers WHERE ad_group_id IS NOT NULL GROUP BY ad_group_id) tg
        LEFT JOIN ad_groups ag ON ag.ad_group_id = tg.ad_group_id
        ORDER BY tg.campaign_id, tg.ad_group_id
      ) g)
    ) as data`;
    break;
  }

  // ── TEASERS ──
  case 'teasers': {
    const limit = parseInt(params.limit) || 200;
    const offset = parseInt(params.offset) || 0;
    const wheres = [];
    if (params.state) wheres.push(`t.state = '${params.state.replace(/'/g,"''")}' `);
    if (params.campaign_id) wheres.push(`t.campaign_id = ${parseInt(params.campaign_id)}`);
    if (params.ad_group_id) wheres.push(`t.ad_group_id = ${parseInt(params.ad_group_id)}`);
    if (params.geozo_status) wheres.push(`t.geozo_status_id = ${parseInt(params.geozo_status)}`);
    const whereClause = wheres.length ? 'WHERE ' + wheres.join(' AND ') : '';
    const dateFrom = params.date_from || '';
    const dateTo = params.date_to || '';
    let statsJoin, statsColumns;
    if (dateFrom && dateTo) {
      statsJoin = `LEFT JOIN (SELECT ad_id, COALESCE(SUM(money),0) as money, COALESCE(SUM(clicks),0) as clicks, COALESCE(SUM(shows),0) as shows, COALESCE(SUM(confirmed_shows),0) as confirmed_shows, COALESCE(SUM(postbacks_count),0) as postbacks_count, COALESCE(SUM(profit),0) as profit, COALESCE(SUM(postbacks_confirmed_money),0) as postbacks_confirmed_money, COALESCE(SUM(crm_leads),0) as crm_leads, COALESCE(SUM(crm_depositors),0) as crm_depositors, COALESCE(SUM(crm_revenue),0) as crm_revenue FROM ad_stats WHERE date >= '${dateFrom.replace(/'/g,"''")}'::date AND date <= '${dateTo.replace(/'/g,"''")}'::date GROUP BY ad_id) s ON s.ad_id = t.ad_id`;
      statsColumns = `s.money as today_spend, s.clicks as today_clicks, s.shows as today_shows, s.confirmed_shows as today_confirmed_shows, s.postbacks_count as today_leads, s.profit as today_profit, s.postbacks_confirmed_money as today_revenue, s.crm_leads as period_crm_leads, s.crm_depositors as period_crm_depositors, s.crm_revenue as period_crm_revenue`;
    } else {
      statsJoin = `LEFT JOIN ad_stats s ON s.ad_id = t.ad_id AND s.date = CURRENT_DATE`;
      statsColumns = `s.money as today_spend, s.clicks as today_clicks, s.shows as today_shows, s.confirmed_shows as today_confirmed_shows, s.roi as today_roi, s.ctr as today_ctr, s.cpc as today_cpc, s.postbacks_count as today_leads, s.profit as today_profit, s.postbacks_confirmed_money as today_revenue, s.crm_leads as period_crm_leads, s.crm_depositors as period_crm_depositors, s.crm_revenue as period_crm_revenue`;
    }
    sql = `SELECT t.*, ${statsColumns},
      COALESCE(c.name, t.campaign_name) as campaign_name, COALESCE(ag.name, t.group_ad_name) as group_name
      FROM teasers t 
      ${statsJoin}
      LEFT JOIN campaigns c ON c.campaign_id = t.campaign_id
      LEFT JOIN ad_groups ag ON ag.ad_group_id = t.ad_group_id
      ${whereClause} ORDER BY t.campaign_id, t.ad_group_id, t.ad_id DESC LIMIT ${limit} OFFSET ${offset}`;
    break;
  }
  case 'teaser_state': {
    const tid = parseInt(params.id);
    const newState = (params.state || '').replace(/'/g, "''");
    const reason = (params.reason || 'Manual change via admin UI').replace(/'/g, "''");
    sql = `WITH old AS (SELECT id, state, ad_id FROM teasers WHERE id = ${tid})
      UPDATE teasers SET state = '${newState}', state_changed_at = NOW(), state_reason = '${reason}', updated_at = NOW() WHERE id = ${tid};
      INSERT INTO teaser_state_log (teaser_id, ad_id, old_state, new_state, reason, triggered_by)
      SELECT ${tid}, ad_id, state, '${newState}', '${reason}', 'admin_ui' FROM teasers WHERE id = ${tid};
      SELECT 'ok' as result`;
    break;
  }

  // ── BID HISTORY ──
  case 'bid_history': {
    const limit = parseInt(params.limit) || 100;
    const adFilter = params.ad_id ? `WHERE ad_id = ${parseInt(params.ad_id)}` : '';
    sql = `SELECT * FROM bid_history ${adFilter} ORDER BY changed_at DESC LIMIT ${limit}`;
    break;
  }

  // ── ANOMALIES ──
  case 'anomalies': {
    const resolved = params.resolved === true || params.resolved === 'true';
    sql = `SELECT * FROM anomalies WHERE resolved = ${resolved} ORDER BY detected_at DESC LIMIT 100`;
    break;
  }
  case 'anomaly_resolve': {
    sql = `UPDATE anomalies SET resolved = TRUE, resolved_at = NOW() WHERE id = ${parseInt(params.id)}; SELECT 'ok' as result`;
    break;
  }

  // ── EMERGENCY ──
  case 'emergency_list': {
    sql = `SELECT * FROM emergency_state ORDER BY activated_at DESC LIMIT 5`;
    break;
  }
  case 'emergency_activate': {
    const reason = (params.reason || 'Manual via admin UI').replace(/'/g, "''");
    const hours = parseFloat(params.hours) || 2;
    sql = `INSERT INTO emergency_state (is_active, trigger_reason, triggered_by, activated_at, auto_deactivate_at)
      VALUES (TRUE, '${reason}', 'admin_ui', NOW(), NOW() + make_interval(hours => ${hours}))
      ON CONFLICT (is_active) WHERE is_active = TRUE
      DO UPDATE SET trigger_reason = EXCLUDED.trigger_reason, activated_at = NOW(), auto_deactivate_at = NOW() + make_interval(hours => ${hours});
      SELECT 'ok' as result`;
    break;
  }
  case 'emergency_deactivate': {
    sql = `UPDATE emergency_state SET is_active = FALSE, deactivated_at = NOW() WHERE is_active = TRUE; SELECT 'ok' as result`;
    break;
  }
  case 'conservative_activate': {
    const mins = parseInt(params.minutes) || 30;
    sql = `INSERT INTO workflow_locks (lock_name, locked_by, expires_at)
      VALUES ('conservative_mode', 'admin_ui', NOW() + make_interval(mins => ${mins}))
      ON CONFLICT (lock_name) DO UPDATE SET locked_by = 'admin_ui', locked_at = NOW(), expires_at = NOW() + make_interval(mins => ${mins});
      SELECT 'ok' as result`;
    break;
  }
  case 'conservative_deactivate': {
    sql = `DELETE FROM workflow_locks WHERE lock_name = 'conservative_mode'; SELECT 'ok' as result`;
    break;
  }

  // ── BLOCK LISTS ──
  case 'block_lists': {
    const typeFilter = params.type ? `WHERE list_type = '${params.type.replace(/'/g,"''")}'` : '';
    sql = `SELECT * FROM block_lists ${typeFilter} ORDER BY added_at DESC LIMIT 200`;
    break;
  }
  case 'block_list_delete': {
    sql = `DELETE FROM block_lists WHERE id = ${parseInt(params.id)}; SELECT 'ok' as result`;
    break;
  }

  // ── LOCKS ──
  case 'locks': {
    sql = `SELECT * FROM workflow_locks ORDER BY locked_at DESC`;
    break;
  }
  case 'lock_delete': {
    sql = `DELETE FROM workflow_locks WHERE lock_name = '${(params.name||'').replace(/'/g,"''")}'; SELECT 'ok' as result`;
    break;
  }

  // ── DAILY PNL ──
  case 'daily_pnl': {
    sql = `SELECT * FROM daily_pnl ORDER BY date DESC LIMIT 30`;
    break;
  }

  // ── SCAN TARGETS ──
  case 'scan_targets': {
    sql = `SELECT * FROM scan_targets ORDER BY id`;
    break;
  }
  case 'scan_target_create': {
    const f = params.fields || {};
    sql = `INSERT INTO scan_targets (site_url, country_code, proxy_url, proxy_type, timezone, accept_language, is_active, notes)
      VALUES ('${(f.site_url||'').replace(/'/g,"''")}', '${(f.country_code||'').replace(/'/g,"''")}', ${f.proxy_url ? "'" + f.proxy_url.replace(/'/g,"''") + "'" : 'NULL'}, '${f.proxy_type||'socks5'}', ${parseInt(f.timezone)||3}, ${f.accept_language ? "'" + f.accept_language.replace(/'/g,"''") + "'" : 'NULL'}, ${f.is_active !== false}, ${f.notes ? "'" + f.notes.replace(/'/g,"''") + "'" : 'NULL'});
      SELECT 'ok' as result`;
    break;
  }
  case 'scan_target_update': {
    const id = parseInt(params.id);
    const sets = [];
    for (const [k, v] of Object.entries(params.fields || {})) {
      if (['site_url','country_code','proxy_url','proxy_type','timezone','accept_language','notes'].includes(k)) {
        sets.push(`${k} = '${String(v).replace(/'/g, "''")}'`);
      }
    }
    if (sets.length === 0) { return [{ json: { error: 'No fields to update' } }]; }
    sql = `UPDATE scan_targets SET ${sets.join(', ')} WHERE id = ${id}; SELECT 'ok' as result`;
    break;
  }
  case 'scan_target_toggle': {
    sql = `UPDATE scan_targets SET is_active = ${params.active === true} WHERE id = ${parseInt(params.id)}; SELECT 'ok' as result`;
    break;
  }
  case 'scan_target_delete': {
    sql = `DELETE FROM scan_targets WHERE id = ${parseInt(params.id)}; SELECT 'ok' as result`;
    break;
  }

  // ── COMPETITORS (SPY TOOL) ──
  case 'competitors_list': {
    const limit = parseInt(params.limit) || 50;
    const offset = parseInt(params.offset) || 0;
    const wheres = [];
    if (params.geo) wheres.push(`country_code = '${params.geo.replace(/'/g,"''")}' `);
    if (params.site_url) wheres.push(`site_url = '${params.site_url.replace(/'/g,"''")}' `);
    if (params.search) wheres.push(`(title ILIKE '%${params.search.replace(/'/g,"''").replace(/%/g,'')}%' OR short_description ILIKE '%${params.search.replace(/'/g,"''").replace(/%/g,'')}%')`);
    if (params.date_from) wheres.push(`last_seen_at >= '${params.date_from.replace(/'/g,"''")}'::date`);
    if (params.date_to) wheres.push(`last_seen_at <= '${params.date_to.replace(/'/g,"''")}'::date + interval '1 day'`);
    if (params.landing_domain) wheres.push(`landing_domain = '${params.landing_domain.replace(/'/g,"''")}' `);
    const whereClause = wheres.length ? 'WHERE ' + wheres.join(' AND ') : '';
    const sortBy = ['last_seen_at','first_seen_at','times_seen','title'].includes(params.sort_by) ? params.sort_by : 'last_seen_at';
    const sortDir = params.sort_dir === 'ASC' ? 'ASC' : 'DESC';
    sql = `SELECT *, (SELECT COUNT(*) FROM competitors ${whereClause}) as total_count FROM competitors ${whereClause} ORDER BY ${sortBy} ${sortDir} LIMIT ${limit} OFFSET ${offset}`;
    break;
  }
  case 'competitors_stats': {
    sql = `SELECT json_build_object(
      'total', (SELECT COUNT(*) FROM competitors),
      'by_geo', (SELECT COALESCE(json_agg(row_to_json(t)), '[]'::json) FROM (SELECT country_code, COUNT(*) as cnt FROM competitors WHERE country_code IS NOT NULL GROUP BY country_code ORDER BY cnt DESC) t),
      'by_day', (SELECT COALESCE(json_agg(row_to_json(t)), '[]'::json) FROM (SELECT last_seen_at::date as day, COUNT(*) as cnt FROM competitors WHERE last_seen_at >= NOW() - interval '30 days' GROUP BY last_seen_at::date ORDER BY day DESC) t),
      'top_domains', (SELECT COALESCE(json_agg(row_to_json(t)), '[]'::json) FROM (SELECT landing_domain, COUNT(*) as cnt FROM competitors WHERE landing_domain IS NOT NULL GROUP BY landing_domain ORDER BY cnt DESC LIMIT 10) t),
      'top_sites', (SELECT COALESCE(json_agg(row_to_json(t)), '[]'::json) FROM (SELECT site_url, COUNT(*) as cnt FROM competitors GROUP BY site_url ORDER BY cnt DESC LIMIT 10) t)
    ) as data`;
    break;
  }
  case 'competitors_detail': {
    const id = parseInt(params.id);
    sql = `SELECT * FROM competitors WHERE id = ${id}`;
    break;
  }

  // ── AB TESTS ──
  case 'ab_tests': {
    sql = `SELECT * FROM ab_tests ORDER BY started_at DESC LIMIT 50`;
    break;
  }

  // ── POSITION TRACKING ──
  case 'position_tracking': {
    const limit = parseInt(params.limit) || 100;
    const adFilter = params.ad_id ? `WHERE pt.ad_id = ${parseInt(params.ad_id)}` : '';
    sql = `SELECT pt.*, t.title as teaser_title FROM position_tracking pt LEFT JOIN teasers t ON t.ad_id = pt.ad_id ${adFilter} ORDER BY pt.scanned_at DESC LIMIT ${limit}`;
    break;
  }

  // ── PROXY STATUS (DataImpulse) ──
  case 'proxy_status': {
    const configured = !!($env.DATAIMPULSE_LOGIN);
    return [{ json: { sql: "SELECT 'ok' as result", action, proxy: { configured, host: $env.DATAIMPULSE_HOST || 'gw.dataimpulse.com', port: $env.DATAIMPULSE_PORT || '823', proxy_type: $env.DATAIMPULSE_PROXY_TYPE || 'datacenter', login: configured ? ($env.DATAIMPULSE_LOGIN || '').substring(0,4) + '***' : null } } }];
  }

  // ── AUTH ──
  case 'login': {
    const hash = (params.password_hash || '').replace(/'/g, "''");
    sql = `SELECT CASE WHEN EXISTS (SELECT 1 FROM admin_auth WHERE password_hash = '${hash}') THEN 'ok' ELSE 'fail' END as result`;
    break;
  }
  case 'change_password': {
    const oldHash = (params.old_hash || '').replace(/'/g, "''");
    const newHash = (params.new_hash || '').replace(/'/g, "''");
    sql = `UPDATE admin_auth SET password_hash = '${newHash}', updated_at = NOW() WHERE password_hash = '${oldHash}'; SELECT CASE WHEN (SELECT COUNT(*) FROM admin_auth WHERE password_hash = '${newHash}') > 0 THEN 'ok' ELSE 'fail' END as result`;
    break;
  }

  default:
    return [{ json: { error: 'Unknown action: ' + action } }];
}

return [{ json: { sql, action } }];

const action = $('Route Action').first().json.action;
const results = $('Execute SQL').all().map(i => i.json);

// For dashboard and campaigns_tree, unwrap json_build_object
// proxy_status: pass through proxy info from Route Action
if (action === 'proxy_status') {
  const routeData = $('Route Action').first().json;
  return [{ json: routeData.proxy || { configured: false } }];
}

if (['dashboard','campaigns_tree','competitors_stats'].includes(action) && results.length > 0 && results[0].data) {
  const data = typeof results[0].data === 'string' ? JSON.parse(results[0].data) : results[0].data;
  return [{ json: data }];
}

// For config_list, group by category
if (action === 'config_list') {
  const grouped = {};
  results.forEach(r => {
    if (!grouped[r.category]) grouped[r.category] = [];
    grouped[r.category].push(r);
  });
  return [{ json: grouped }];
}

return [{ json: { data: results } }];
